mapper.select:
SELECT SUBJECT_NO as subjectNo, SUBJECT_TITLE as subjectTitle, SUBJECT_INSTRUCTOR as subjectInstructor, SUBJECT_CATEGORY as subjectCategory, SUBJECT_LEVEL as subjectLevel, SUBJECT_COUNT as subjectCount FROM SUBJECT_TBL
AND LOWER(SUBJECT_TITLE) LIKE '%' || LOWER(#{search}) || '%'
AND SUBJECT_CATEGORY = #{category}
AND SUBJECT_LEVEL = #{level}
ORDER BY SUBJECT_LEVEL ASC, SUBJECT_NO SUBJECT_LEVEL DESC, SUBJECT_NO SUBJECT_COUNT DESC, SUBJECT_NO SUBJECT_COUNT ASC, SUBJECT_NO SUBJECT_NO
